+    if (tileIdx < numTiles - 1) {
+#pragma unroll
+      for (int32_t ii = 0; ii < MaxExpandedIdxPerThread; ii += 1) {
+        auto expandedIdx = tileIdx * MaxExpandedIdxPerBlock + ii * NumThreadsHist + threadIdx.x;
+        storeLoopBody(ii, expandedIdx);
